180: nsresult nsObserverService::FilterHttpOnTopics(const char* aTopic) {
181:   // Specifically allow some http-on-* observer notifications in the child
182:   // process.
183:   if (mozilla::net::IsNeckoChild() && !strncmp(aTopic, "http-on-", 8) &&
184:       strcmp(aTopic, "http-on-before-stop-request") &&
185:       strcmp(aTopic, "http-on-failed-opening-request") &&
186:       strcmp(aTopic, "http-on-resource-cache-response") &&
187:       strcmp(aTopic, "http-on-opening-request") &&
188:       strcmp(aTopic, "http-on-stop-request")) {
189:     nsCOMPtr<nsIConsoleService> console(
190:         do_GetService(NS_CONSOLESERVICE_CONTRACTID));
191:     nsCOMPtr<nsIScriptError> error(
192:         do_CreateInstance(NS_SCRIPTERROR_CONTRACTID));
193:     error->Init(u"http-on-* observers only work in the parent process"_ns,
194:                 ""_ns, 0, 0, nsIScriptError::warningFlag,
195:                 "chrome javascript"_ns, false /* from private window */,
196:                 true /* from chrome context */);
197:     console->LogMessage(error);
198: 
199:     return NS_ERROR_NOT_IMPLEMENTED;
200:   }
201: 
202:   return NS_OK;
203: }
