226: NS_IMETHODIMP
227: nsObserverService::RemoveObserver(nsIObserver* aObserver, const char* aTopic) {
228:   LOG(("nsObserverService::RemoveObserver(%p: %s)", (void*)aObserver, aTopic));
229: 
230:   if (mShuttingDown) {
231:     // The service is shutting down. Let's ignore this call.
232:     return NS_OK;
233:   }
234: 
235:   MOZ_TRY(EnsureValidCall());
236:   if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
237:     return NS_ERROR_INVALID_ARG;
238:   }
239: 
240:   nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
241:   if (!observerList) {
242:     return NS_ERROR_FAILURE;
243:   }
244: 
245:   return observerList->RemoveObserver(aObserver);
246: }
