38: nsresult nsAlertsService::Init() {
39:   if (nsCOMPtr<nsIObserverService> obsServ =
40:           mozilla::services::GetObserverService()) {
41:     (void)NS_WARN_IF(
42:         NS_FAILED(obsServ->AddObserver(this, "last-pb-context-exited", false)));
43:   }
44: 
45:   // The shutdown callback holds a strong reference and thus makes sure this
46:   // runs at shutdown.
47:   //
48:   // Note that the purpose of this shutdown cleanup is to make the leak checker
49:   // happy, and an early exit(0) without calling it should not break anything.
50:   // (See also bug 1606879)
51:   RunOnShutdown([self = RefPtr{this}]() { self->Teardown(); });
52: 
53:   return NS_OK;
54: }
